mapper.select:
SELECT *
FROM (
SELECT STOCK_NO AS stockNo, LAT AS lat, LNG AS lng
FROM STOCK_COORD
WHERE LAT > #{swLat}
AND LAT < #{neLat}
AND LNG > #{swLng}
AND LNG < #{neLng}
) c
INNER JOIN (
SELECT *
FROM STOCK_INFO


		AND (STOCK_NAME LIKE '%' || #{searchKeyWord} || '%'
		OR STOCK_NAME LIKE CONCAT(#{searchKeyWord}, '%')
		OR STOCK_NAME LIKE CONCAT('%', #{searchKeyWord})
		OR STOCK_NAME = #{searchKeyWord})




				AND REGION_NO LIKE CONCAT(#{locationCode}, '%')


				AND REGION_NO = #{locationCode}




		AND STOCK_TYPE = #{stockType}


		AND STOCK_FORM = #{stockForm}


) i ON c.stockNo = i.STOCK_NO
LEFT JOIN (
SELECT MEMBER_NO, COMPANY_NAME, COMPANY_LOCATION, PRESIDENT_NAME, BROKER_NO,
PRESIDENT_PHONE
FROM BROKER_INFO
) b ON i.MEMBER_NO = b.MEMBER_NO
LEFT JOIN STOCK_IMG m ON i.STOCK_NO = m.STOCK_NO
LEFT JOIN SELL_DATE sell ON i.STOCK_NO = sell.STOCK_NO
WHERE 
(
	sell.SELL_DATE > ( SYSDATE - 7)
	OR sell.SELL_DATE IS NULL
)
ORDER BY m.IMG_ORDER

SELECT AVG(lat) AS latCenter, AVG(lng) AS lngCenter ,MIN(lat) AS latMin, MIN(lng) AS lngMin ,MAX(lat) AS latMax, MAX(lng) AS lngMax , COUNT(*) FROM ( SELECT STOCK_NO AS stockNo, LAT AS lat, LNG AS lng FROM STOCK_COORD
) c INNER JOIN (SELECT * FROM STOCK_INFO
AND (STOCK_NAME LIKE '%' || #{searchKeyWord} || '%' OR STOCK_NAME LIKE CONCAT(#{searchKeyWord}, '%') OR STOCK_NAME LIKE CONCAT('%', #{searchKeyWord}) OR STOCK_NAME = #{searchKeyWord})
AND REGION_NO LIKE CONCAT(#{locationCode}, '%')
AND REGION_NO = #{locationCode}
AND STOCK_TYPE = #{stockType}
AND STOCK_FORM = #{stockForm}
) i ON c.stockNo = i.STOCK_NO
